                                                 hydra:variable  "created"
                                               ] ;
                               hydra:mapping   [ hydra:property  dc:issued ;
                                                 hydra:required  true ;
                                                 hydra:variable  "issued"
                                               ] ;
                               hydra:mapping   [ hydra:property  :localId ;
