                                           ] ;
                           hydra:mapping   [ hydra:property  dc:issued ;
                                             hydra:required  true ;
                                             hydra:variable  "issued"
                                           ] ;
                           hydra:mapping   [ hydra:property  :localId ;
                                             hydra:required  true ;
                                             hydra:variable  "uuid"
                                           ] ;
                           hydra:template  "https://example.org/id/meetpunt/{uuid}/{issued}/{created}"^^hydra:Rfc6570Template
                         ] .

