        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      pplan:isInputVarOf ;
                           owl:someValuesFrom  :Process
                         ] ;
        skos:example     [ rdf:type    :ProcessVariabele ;
                           rdfs:label  "Flour"@en ;
                           dc:type     [ rdf:type    prov:Entity ;
                                         rdfs:label  "Substance"@en
                                       ]
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  :localId ;
                                             hydra:required  true ;
                                             hydra:variable  "uuid"
                                           ] ;
                           hydra:template  "https://example.org/id/procesvariabele/{uuid}"^^hydra:Rfc6570Template
                         ] .

:Emission  rdf:type          owl:Class ;
        rdfs:comment         "An emission is a specific result that relates to the release or discharge of substances at emission points."@en ;
        rdfs:label           "Emission"@en ;
        rdfs:subClassOf      sosa:Result ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      sosa:isResultOf ;
                               owl:someValuesFrom  sosa:Observation
                             ] ;
        owl:equivalentClass  [ rdf:type            owl:Restriction ;
                               rdfs:comment        "An emission must be linked to a process variable that is used within a process (as output) that is implemented by an emission point"@en ;
                               owl:onProperty      pplan:correspondsToVariable ;
                               owl:someValuesFrom  [ rdf:type            owl:Restriction ;
                                                     owl:onProperty      pplan:isOutputVarOf ;
                                                     owl:someValuesFrom  [ rdf:type            owl:Restriction ;
                                                                           owl:onProperty      ssn:implementedBy ;
                                                                           owl:someValuesFrom  :Emissionpunt
                                                                         ]
                                                   ]
                             ] .

